export enum EVENTS{
  BACK,
  INIT,
  MSG,
  PROGRESS,
  START,
  STOP,
  SUBMIT  
}

export const init = ():void=>{
  window.parent.postMessage({event:EVENTS.INIT,events:EVENTS});
}

export const postMessage = (event:EVENTS,message:string):void=>{
  window.parent.postMessage({event,message});
}

export const message=(callback:Function):void=>{
  window.addEventListener("message", (event:Event):void=>{
     callback(event);
  })
}